// 5 次元 typedef 配列ローカル変数の最深 stride チェック。
// M5 = int[2][2][2][2][2] なので 32 要素、各 4 byte で計 128 byte。
// strides:
//   outer = 16*4=64, mid = 8*4=32, extra=[16, 8, 4]
// a[1][1][1][1][1] = 31, a[0][0][0][0][0] = 1。差 = 30。
// 期待: exit=30
typedef int M5[2][2][2][2][2];
int main(void) {
    M5 a;
    a[1][1][1][1][1] = 31;
    a[0][0][0][0][0] = 1;
    return a[1][1][1][1][1] - a[0][0][0][0][0];
}
